import os
from fastapi import FastAPI, Depends, Request
from fastapi.security import OAuth2PasswordBearer, OAuth2PasswordRequestForm
from redis import Redis

redis_host = os.getenv("REDIS_HOST")
redis_port = int(os.getenv("REDIS_PORT"))
redis_db = int(os.getenv("REDIS_DB"))

app = FastAPI()

oauth2_scheme = OAuth2PasswordBearer(tokenUrl="/token")

@app.post("/login")
async def login(form: OAuth2PasswordRequestForm = Depends()):
    # Implement your own login logic here
    return {"access_token": "YOUR_ACCESS_TOKEN"}

@app.get("/protected")
async def protected(token: str = Depends(oauth2_scheme)):
    # Check if token exists in Redis cache
    redis = Redis(host=redis_host, port=redis_port, db=redis_db)
    if not redis.exists(token):
        return {"message": "Token not found"}
    
    # If token exists, proceed with the request
    return {"message": "Protected endpoint accessed successfully"}